INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('stockholm-wool-flatweave', 'pt', 'Stockholm Flatweave em Lã', 'Flatweave tecido à mão em lã macia com padrão espinha subtil. Pile baixo, ideal para salas de jantar e zonas de maior circulação.', 'Aspire regularmente. Limpeza profissional recomendada uma vez por ano.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('oslo-berber-shag', 'pt', 'Oslo Shag Berber', 'Pile exuberante estilo Berber com textura orgânica. Aquece e dá profundidade a quartos e cantos de leitura.', 'Abane ao ar livre ocasionalmente. Limpe manchas com detergente suave.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('copenhagen-jute-natural', 'pt', 'Copenhagen Juta Natural', 'Juta de origem sustentável com borda trançada. Perfeita para entradas e composições em camadas na sala.', 'Apenas limpeza a seco. Evite humidade prolongada.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('helsinki-geometric-wool', 'pt', 'Helsinki Geométrico em Lã', 'Motivo geométrico inspirado em azulejos nórdicos. Pile denso em lã, confortável e com boa absorção acústica.', 'Rode a cada 6 meses. Limpeza profissional para lã.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('gothenburg-vintage-persian', 'pt', 'Gothenburg Persa Vintage', 'Tecido à máquina com acabamento vintage desgastado. Medalhão rico que dá carácter a salas de jantar formais.', 'Aspire em potência baixa, sem escova rotativa.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('malmo-outdoor-polypropylene', 'pt', 'Malmö Exterior em Polipropileno', 'Resistente a UV e fácil de lavar com mangueira. Tecelagem plana ideal para varandas, terraços e jardins de inverno.', 'Enxague com água. Deixe secar completamente ao ar.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('aarhus-kids-play-rug', 'pt', 'Aarhus Tapete de Brincar Infantil', 'Algodão macio com padrão de estrada. Base antiderrapante e lavável na máquina, para famílias ativas.', 'Lavar à máquina a frio. Secar no estendal.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('bergen-silk-viscose', 'pt', 'Bergen Seda-Viscose', 'Mistura seda-viscose com brilho e design abstrato em aguarela. Ponto focal elegante em suites principais.', 'Apenas limpeza a seco profissional.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('tromso-high-pile-shag', 'pt', 'Tromsø Shag de Pile Alto', 'Pile ultra-macio para conforto descalço. Fibras resistentes a nódoas, ideais para salas familiares.', 'Aspire com bocal de estofos. Evite escova rotativa.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('uppsala-runner-collection', 'pt', 'Coleção Passadeira Uppsala', 'Passadeiras estreitas para corredores e cozinhas. Design reversível com borda contrastante.', 'Lavar à máquina em ciclo delicado.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('lund-minimal-flatweave', 'pt', 'Lund Flatweave Minimal', 'Tom sólido com franja tonal. A base escandinava por excelência para qualquer interior.', 'Aspire ambos os lados mensalmente.');
INSERT OR REPLACE INTO product_translations (slug, locale, name, description, care) VALUES ('narvik-moroccan-beni', 'pt', 'Narvik Beni Marroquino', 'Padrão de losangos inspirado em Beni Ourain autêntico. Pile espesso em lã para luxo sob os pés.', 'Limpeza profissional. Abane e areje periodicamente.');
